// LESSON: Collectors Recipes - Reference Page 2.
// You will learn: Collect streams into lists, maps, groups, partitions, and summaries.
import java.util.Arrays;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

class CollectorsRecipesReference {
  public static void main(String[] args) {
    example1CollectListAndText();
    example2CollectToMap();
    example3GroupAndCount();
  }

  static void example1CollectListAndText() {
    List<String> names = Arrays.asList("Alva", "Bo", "Cleo", "Dina");
    List<String> shortNames = names.stream().filter(name -> name.length() <= 4).collect(Collectors.toList());
    String joined = names.stream().collect(Collectors.joining(", "));
    System.out.println(shortNames);
    System.out.println(joined);
  }

  static void example2CollectToMap() {
    List<CollectorPerson> people = Arrays.asList(new CollectorPerson("p1", "Alva", "Lund"), new CollectorPerson("p2", "Bo", "Mora"), new CollectorPerson("p3", "Cleo", "Lund"));
    Map<String, CollectorPerson> byId = people.stream().collect(Collectors.toMap(CollectorPerson::id, person -> person));
    CollectorPerson found = byId.get("p2");
    System.out.println(found);
  }

  static void example3GroupAndCount() {
    List<CollectorPerson> people = Arrays.asList(new CollectorPerson("p1", "Alva", "Lund"), new CollectorPerson("p2", "Bo", "Mora"), new CollectorPerson("p3", "Cleo", "Lund"));
    Map<String, List<CollectorPerson>> byCity = people.stream().collect(Collectors.groupingBy(CollectorPerson::city));
    Map<String, Long> countByCity = people.stream().collect(Collectors.groupingBy(CollectorPerson::city, Collectors.counting()));
    System.out.println(byCity);
    System.out.println(countByCity);
  }
}

class CollectorPerson {
  private final String id;
  private final String name;
  private final String city;

  CollectorPerson(String id, String name, String city) {
    this.id = id;
    this.name = name;
    this.city = city;
  }

  String id() { return id; }
  String city() { return city; }
  public String toString() { return name + " from " + city; }
}
